import{c as e,cG as a,cb as t,c8 as r,cf as l,cT as i,ce as c,ab as n,aN as o,bf as s}from"./chunks/framework.BlkIsu1j.js";const h=JSON.parse('{"title":"【键盘】ikbc键盘Win键失效","description":"","frontmatter":{"title":"【键盘】ikbc键盘Win键失效","categories":"键盘","tags":["ibkc","键盘"],"sidebar":false,"prev":false,"next":false,"comments":false,"date":"2024-09-11T12:50:05.000Z"},"headers":[],"relativePath":"posts/2024/09_11_ikbc键盘Win键失效.md","filePath":"posts/2024/09_11_ikbc键盘Win键失效.md","lastUpdated":1746281966000}'),d={id:"frontmatter-title",tabindex:"-1"};const p=e({name:"posts/2024/09_11_ikbc键盘Win键失效.md"},[["render",function(e,h,p,m,b,f){return a(),t("div",null,[r("h1",d,[l(i(e.$frontmatter.title)+" ",1),h[0]||(h[0]=r("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),h[1]||(h[1]=c('<blockquote><p>如题，键盘的 Win 键无法使用、使用无效</p></blockquote><h2 id="分析" tabindex="-1">分析 <a class="header-anchor" href="#分析" aria-label="Permalink to “分析”">​</a></h2><p>系统： macOS + ikbc键盘</p><ul><li>系统问题：系统键盘设置、其他软件</li><li>键盘问题：键盘按键坏了、键盘设置</li></ul><h3 id="macos-上改过按键" tabindex="-1">macOS 上改过按键： <a class="header-anchor" href="#macos-上改过按键" aria-label="Permalink to “macOS 上改过按键：”">​</a></h3><p>Win(Command) 键和 Alt(Option) 键交换了位置，<a href="https://support.apple.com/zh-cn/guide/mac-help/mchlp1011/mac" target="_blank" rel="noreferrer">https://support.apple.com/zh-cn/guide/mac-help/mchlp1011/mac</a></p><img src="'+n+'" alt="image-2024091111025332 PM" style="zoom:50%;"><h3 id="使用软键盘-keyboard-viewer" tabindex="-1">使用软键盘 Keyboard Viewer <a class="header-anchor" href="#使用软键盘-keyboard-viewer" aria-label="Permalink to “使用软键盘 Keyboard Viewer”">​</a></h3><img src="'+o+'" alt="image-2024091111745234 PM" style="zoom:50%;"><img src="'+s+'" alt="image-2024091110102324 PM" style="zoom:50%;"><p>这时候 Win 键也是可以使用的，系统是能响应；但从键盘上按 Win 无效，然后转向从 ikbc 键盘入手去找原因</p><h2 id="解决问题" tabindex="-1">解决问题 <a class="header-anchor" href="#解决问题" aria-label="Permalink to “解决问题”">​</a></h2><p>ikbc键盘win按键失灵问题。其实是自己不小心把win键给锁定了。</p><p>下面是介绍一下ikbc键盘上，锁定win键和解锁win键的方法，如下表所示：</p><table tabindex="0"><thead><tr><th>键盘款式</th><th>锁定的方法</th><th>解锁的方法</th></tr></thead><tbody><tr><td>非静音款</td><td><code>Fn + 左Win</code></td><td><code>Fn + 右Win</code></td></tr><tr><td>静音款</td><td><code>Fn + F12</code></td><td><code>Fn + PrtSc</code></td></tr></tbody></table><p>按照上面的解锁方法， 我的<code>ikbc c87</code>键盘按了 <code>Fn + 右Win</code>就成功激活了Win键。</p><blockquote><p>注意按键的顺序：先按<strong>Fn键</strong>，按住后别松开，再接着按<strong>右win键</strong>。</p></blockquote><h2 id="references" tabindex="-1">References： <a class="header-anchor" href="#references" aria-label="Permalink to “References：”">​</a></h2><ul><li>修改修饰符按键：<a href="https://support.apple.com/zh-cn/guide/mac-help/mchlp1011/mac" target="_blank" rel="noreferrer">https://support.apple.com/zh-cn/guide/mac-help/mchlp1011/mac</a></li><li>解决参考：<a href="https://javaforall.cn/137781.html" target="_blank" rel="noreferrer">https://javaforall.cn/137781.html</a></li><li><a href="https://www.phpsdk.cn/plug/news/show.html?id=11032" target="_blank" rel="noreferrer">https://www.phpsdk.cn/plug/news/show.html?id=11032</a></li></ul>',19))])}]]);export{h as __pageData,p as default};
